insert into public.itineraries (
  slug_fr, slug_en, title_fr, title_en,
  meta_title_fr, meta_title_en, meta_desc_fr, meta_desc_en,
  intro_fr, intro_en,
  aeo_question_fr, aeo_answer_fr, aeo_question_en, aeo_answer_en,
  country_code, destination_region, destination_city, themes,
  duration_min_days, duration_max_days, travel_style, season,
  hotel_ids, sections, faq_content,
  related_ranking_ids, related_guide_slugs, related_itinerary_slugs,
  last_updated, status, priority, word_count_target
) values (
  'japon-luxe-7-jours',
  'japan-luxury-7-days',
  'Itinéraire Tokyo, Kyoto, Hakone 7 jours — luxe',
  'Tokyo, Kyoto, Hakone 7-day luxe itinerary',
  'Itinéraire Japon 7 jours luxe — Tokyo, Kyoto, Hakone | MyConciergeHotel',
  'Itinerary Tokyo, Kyoto, Hakone 7 days | MyConciergeHotel',
  '7 jours au Japon entre Tokyo, Kyoto et Hakone : Palaces 5★, kaiseki étoilés, période des cerisiers. Sélection Concierge avec hôtels réservables.',
  'A 7-day luxe itinerary in Tokyo, Kyoto, Hakone. Concierge timings, luxury hotels, luxe, culture, gastronomie highlights, and verified bookable addresses.',
  'Ce voyage de 7 jours au Japon relie Tokyo, Hakone et Kyoto dans un tempo luxe, précis et respirable. Vous alternez trois étapes bien calibrées, entre énergie urbaine, pause thermale et profondeur patrimoniale, avec Aman Tokyo puis Park Hyatt Kyoto comme points d’ancrage. Comptez environ 11 500 à 16 500 EUR TTC pour deux, vols internationaux en sus, selon la catégorie de chambre et les tables retenues. La meilleure fenêtre va d’octobre à novembre, puis de mars à avril, avec une logistique simple entre Tokyo et Odawara en 35 minutes de shinkansen. Côté coulisses, descendez au spa de l’Aman Tokyo avant 7h pour profiter seul de la piscine de 30 mètres. À Kyoto, demandez les chambres 3902 ou 3905 au Park Hyatt Kyoto, plus justes que certaines “temple view”. Pour la table, Kikunoi compte 3 étoiles Michelin dans le Guide Michelin Kyoto Osaka 2024.',
  'This 7-day Japan itinerary moves through Tokyo, Hakone and Kyoto with a measured luxury rhythm. It unfolds in three well-balanced stops, mixing city intensity, restorative downtime and cultural depth, with Aman Tokyo and Hakone Ginyu setting the tone. Expect roughly 11,500 to 16,500 EUR TTC for two, excluding international flights, depending on room category and dining choices. The easiest seasons are October to November and March to April, when weather is stable and transfers stay smooth. Tokyo to Odawara takes 35 minutes by shinkansen, so the shift to Hakone feels light rather than logistical. One detail worth knowing early: go down to the Aman Tokyo spa before 7am for near-private access to the 30-metre pool. In Kyoto, ask specifically for room 3902 or 3905 at Park Hyatt Kyoto, with a better Yasaka Pagoda angle than several standard temple-view rooms. Kikunoi holds 3 Michelin stars in the Michelin Guide Kyoto Osaka 2024.',
  'Quel est le meilleur itinéraire pour le Japon en 7 jours en luxe ?',
  'Tokyo (2 nuits Aman Tokyo, Otemachi), Hakone (2 nuits ryokan Ginyu, vue Fuji, onsen), Kyoto (3 nuits Park Hyatt, Fushimi Inari, kaiseki Kikunoi). Période idéale : fin mars-début avril (cerisiers) ou novembre (momiji). Japan Rail Pass 7 jours couvre Tokyo-Hakone-Kyoto. Mis à jour mai 2026.',
  'What is the best 7-day itinerary for Tokyo, Kyoto, Hakone?',
  '7-day luxury Japan: Tokyo, Hakone, and Kyoto. Day 1: Senso-ji, Ginza, TeamLab Borderless. Day 2: Mount Fuji views, Hakone Open-Air Museum, Lake Ashi. Day 3: Fushimi Inari, Arashiyama bamboo grove, Kinkaku-ji. Base at Aman Tokyo; ask for a high-floor corner room. Spring, ideally late March to April. Updated May 2026.',
  'JP',
  'Honshu',
  'Tokyo, Kyoto, Hakone',
  array['luxe', 'culture', 'gastronomie']::text[],
  7::smallint,
  7::smallint,
  'luxe',
  'printemps',
  array['d5acea07-c82e-42a5-9861-7bd063dc633d', '6eee364d-d7a8-4352-9ca2-43d899d8a0a1', '599a05ae-1eb3-4cdf-927d-64d8da06b65c']::uuid[],
  '[{"step":1,"title_fr":"Jours 1-2 : Tokyo — Immersion dans la mégapole","title_en":"Days 1-2: Tokyo — Megacity immersion","body_fr":"Tokyo s’ouvre ici par Otemachi, entre tours calmes, accès millimétrés et départs très simples vers l’est historique comme vers les vitrines de Ginza.\n\nDepuis l’Aman Tokyo, partez tôt pour Senso-ji, avant 8h30, quand Nakamise reste encore fluide. Comptez 20 à 25 minutes en taxi selon le trafic. Revenez ensuite vers Hama-rikyu pour une marche de fin de matinée, plus lisible avant l’arrivée des groupes. Ce jardin de l’époque Edo, classé site spécial au Japon, se prête bien à une entrée par Shiodome puis à une sortie vers la Sumida. L’après-midi, réservez TeamLab Borderless sur un créneau d’ouverture ou après 19h. Les billets horodatés partent vite. Gardez Ginza pour le soir, quand les comptoirs travaillent avec plus de précision et que les transferts restent courts.\n\nÀ l’Aman Tokyo, demandez au concierge un check-in préparé avec accès spa immédiat et voiture réservée pour Asakusa au premier matin. Pour dîner, Sukiyabashi Jiro reste une maison de référence Michelin. La réservation se traite longtemps en amont, souvent via le concierge, avec horaire imposé et politique d’annulation stricte.\n\nMon conseil : descendez au spa de l’Aman avant 7h. Vous aurez souvent la piscine de 30 mètres face à la Skytree presque pour vous seul, sans attente ni bruit.","body_en":"Tokyo begins in Otemachi, where quiet towers, controlled access, and easy departures make the city feel readable from the start. From Aman Tokyo, leave early for Senso-ji, ideally before 8:30, while Nakamise is still moving well. The taxi ride is usually 20 to 25 minutes, depending on traffic. After that, return to Hamarikyu for a late-morning walk, before the groups arrive. This Edo-period garden, designated a Special Place of Scenic Beauty in Japan, works best if you enter via Shiodome and leave toward the Sumida. In the afternoon, book TeamLab Borderless for opening time or after 7:00 pm. Timed tickets go quickly. Keep Ginza for the evening, when the counters work with more precision and transfers stay short. At Aman Tokyo, ask the concierge for a prepared check-in with immediate spa access and a car reserved for Asakusa on the first morning. For dinner, Sukiyabashi Jiro remains a Michelin reference house, with reservations handled well in advance, usually through the concierge, with fixed timing and strict cancellation terms. My advice: go down to the Aman spa before 7:00 am. You will often have the 30-metre pool facing the Skytree almost to yourself, with no wait and no noise.","hotel_id":"d5acea07-c82e-42a5-9861-7bd063dc633d","duration_days":2,"city":"Tokyo","poi":["Senso-ji","Ginza","TeamLab Borderless","Hamarikyu"]},{"step":2,"title_fr":"Jours 3-4 : Hakone — Ryokan, onsen et vue sur le Fuji","title_en":"Days 3-4: Hakone — Ryokan, onsen and Fuji views","body_fr":"Hakone ralentit le rythme sans compliquer la logistique, avec un passage net de Tokyo à l’eau thermale, aux pentes volcaniques et aux vues dégagées sur le Fuji.\n\nDepuis Tokyo, prenez le shinkansen jusqu’à Odawara, 35 minutes environ, puis faites organiser le transfert par Hakone Ginyu. Le premier jour, visez le Musée en Plein Air de Hakone en fin de matinée, quand la lumière sert mieux les sculptures et que les circulations restent simples. Poursuivez vers Owakudani selon l’activité volcanique et l’ouverture du téléphérique, variables selon le vent et les émissions. Le lendemain, partez tôt pour le lac Ashi. Une croisière matinale donne les vues les plus nettes sur le mont Fuji, avant la brume de milieu de journée. Gardez ensuite du temps au ryokan plutôt que d’ajouter des trajets inutiles.\n\nHakone Ginyu est un ryokan de référence avec bains privatifs en chambre. Demandez une chambre avec bain orienté sur la vallée et un dîner servi au plus tard à 18h30 pour préserver une vraie séquence onsen avant la nuit. Pour la table, le kaiseki du ryokan est le choix le plus cohérent. Il faut signaler allergies, rythme de service souhaité et préférence pour petit-déjeuner japonais ou occidental dès la confirmation.\n\nMon conseil : demandez au concierge de caler votre départ vers le lac Ashi avant 8h15 et de vérifier la visibilité Fuji la veille au soir. À Hakone, c’est ce réglage horaire qui change tout.","body_en":"Hakone slows the pace without complicating the logistics. It is a clean shift from Tokyo to hot water, volcanic slopes, and open views of Fuji. From Tokyo, take the shinkansen to Odawara, about 35 minutes, then let Hakone Ginyu arrange the transfer. On day one, aim for the Hakone Open-Air Museum late in the morning, when the light works better for the sculptures and movement is simpler. Continue to Owakudani, depending on volcanic activity and ropeway operations, which vary with wind and emissions. The next day, leave early for Lake Ashi. A morning cruise gives the clearest Fuji views, before the mid-day haze. Keep the rest of the day at the ryokan rather than adding unnecessary transfers. Hakone Ginyu is a reference ryokan with private baths in the room. Ask for a room with a bath facing the valley, and for dinner to be served no later than 6:30 pm, so you keep a proper onsen sequence before nightfall. For the table, the ryokan kaiseki is the most coherent choice. Declare allergies, preferred service pace, and whether you want a Japanese or Western breakfast at confirmation. My advice: ask the concierge to set your Lake Ashi departure before 8:15 am and to check Fuji visibility the night before. In Hakone, that timing changes everything.","hotel_id":"599a05ae-1eb3-4cdf-927d-64d8da06b65c","duration_days":2,"city":"Hakone","poi":["Mont Fuji vue","Musée en Plein Air Hakone","Lac Ashi","Onsen Owakudani"]},{"step":3,"title_fr":"Jours 5-7 : Kyoto — Capitale impériale, temples et kaiseki","title_en":"Days 5-7: Kyoto — Imperial capital, temples and kaiseki","body_fr":"Kyoto se vit ici depuis Higashiyama, à pied tôt le matin, puis par séquences très réglées entre temples, ruelles et tables de kaiseki.\n\nDepuis le Park Hyatt Kyoto, commencez par Kiyomizu-dera avant 8h. Le temple, inscrit avec les Monuments historiques de l’ancienne Kyoto au patrimoine mondial de l’UNESCO, se lit mieux avant l’affluence. Revenez ensuite par les pentes de Higashiyama, puis gardez Gion pour 17h, quand le quartier retrouve son tempo de fin d’après-midi. Le lendemain, partez tôt vers Fushimi Inari. Une arrivée avant 7h30 permet de franchir les premiers torii sans rupture de flux. Réservez Arashiyama pour le début de matinée suivant, bambouseraie d’abord, puis transfert vers Kinkaku-ji avant le pic de groupes de fin de matinée.\n\nAu Park Hyatt Kyoto, demandez une voiture pour Arashiyama au lever du jour et un départ discret vers Fushimi Inari avant le service du petit-déjeuner. Pour dîner, Kikunoi Honten, trois étoiles Michelin, reste la référence du kaiseki à Kyoto. Réservation indispensable plusieurs semaines, parfois davantage, avec confirmation des restrictions alimentaires et tenue soignée.\n\nMon conseil : au Park Hyatt Kyoto, demandez les chambres 3902 ou 3905, côté pagode Yasaka. La vue y est souvent mieux cadrée que dans plusieurs catégories annoncées comme “temple view”.","body_en":"Kyoto is best lived from Higashiyama, on foot early in the morning, then in tightly managed sequences between temples, lanes, and kaiseki tables. From Park Hyatt Kyoto, start with Kiyomizu-dera before 8:00 am. The temple, listed with the Historic Monuments of Ancient Kyoto as a UNESCO World Heritage site, reads better before the crowds. Come back through the slopes of Higashiyama, then keep Gion for around 5:00 pm, when the district settles into its late-afternoon rhythm. The next day, leave early for Fushimi Inari. Arriving before 7:30 am lets you pass the first torii without breaking the flow. Reserve Arashiyama for the following morning, starting with the bamboo grove, then transfer to Kinkaku-ji before the late-morning group peak. At Park Hyatt Kyoto, ask for a car to Arashiyama at daybreak and a discreet departure to Fushimi Inari before breakfast service. For dinner, Kikunoi Honten, a three-Michelin-star house, remains Kyoto’s kaiseki benchmark. Book several weeks ahead, sometimes longer, and confirm dietary restrictions and proper attire. My advice: at Park Hyatt Kyoto, ask for rooms 3902 or 3905, on the Yasaka Pagoda side. The framing there is often better than in several categories sold as “temple view”.","hotel_id":"6eee364d-d7a8-4352-9ca2-43d899d8a0a1","duration_days":3,"city":"Kyoto","poi":["Fushimi Inari","Arashiyama (bambouseraie)","Kinkaku-ji","Kiyomizu-dera"]}]'::jsonb,
  '[{"q_fr":"Quelle est la meilleure période pour visiter le Japon ?","a_fr":"Pour Tokyo, Kyoto et Hakone, visez fin mars à mi-avril pour les cerisiers, ou mi-octobre à fin novembre pour les érables. Avril et novembre donnent le meilleur équilibre entre climat, jardins et rythme culturel. Évitez la Golden Week, fin avril à début mai, avec forte pression sur trains et hôtels. En juin, la pluie pèse sur Kyoto. Secret utile : à Hakone, partez en téléphérique avant 9h pour une vue plus dégagée sur le Fuji. Mis à jour mai 2026.","q_en":"When is the best time to visit Japan?","a_en":"For Tokyo, Kyoto, and Hakone, aim for late March to mid-April for cherry blossom, or mid-October to late November for autumn foliage. April and November offer the best balance of weather, gardens, and cultural pace. Avoid Golden Week, usually late April to early May, when trains and hotels are under heavy pressure. June is wetter, especially in Kyoto. Practical tip: in Hakone, take the ropeway before 9 a.m. for clearer Mt. Fuji views. Updated May 2026."},{"q_fr":"Combien de jours faut-il pour découvrir le Japon ?","a_fr":"Pour un premier voyage luxe, 7 jours suffisent pour un triptyque Tokyo, Kyoto, Hakone. Comptez 3 nuits à Tokyo, 2 à Kyoto, 1 à Hakone, puis retour. En dessous, le rythme devient trop serré. Pour vraiment approfondir, 10 à 12 jours sont plus justes, avec Kanazawa ou Naoshima en plus. Sur 7 jours, gardez des transferts simples en Shinkansen et limitez les check-in tardifs. C’est ce qui préserve le confort du voyage.","q_en":"How many days do you need to discover Japan?","a_en":"For a first luxury trip, seven days works well for a Tokyo, Kyoto, and Hakone circuit. Plan three nights in Tokyo, two in Kyoto, one in Hakone, then return. Less than that feels rushed. If you want more depth, ten to twelve days is a better frame, with Kanazawa or Naoshima added. On a seven-day itinerary, keep transfers simple by Shinkansen and avoid late hotel arrivals. That is what protects the comfort of the trip."},{"q_fr":"Quel budget prévoir pour un itinéraire luxe Japon 7 jours ?","a_fr":"Pour 7 jours en profil luxe, prévoyez environ 8 500 à 15 000 € TTC pour deux, hors vols long-courriers. Ce cadre couvre Aman Tokyo, Park Hyatt Kyoto et Hakone Ginyu, avec petit déjeuner, transferts en train premium, quelques taxis, un dîner étoilé Michelin et un ryokan avec dîner kaiseki. Avec guide privé sur deux journées et réservations très demandées, visez plutôt 12 000 à 18 000 € TTC. Le vrai écart vient surtout des catégories de chambre et des repas.","q_en":"What budget should you plan for a 7-day luxury Japan itinerary?","a_en":"For seven days at a luxury level, plan roughly EUR 8,500 to EUR 15,000 including taxes for two, excluding long-haul flights. That range covers Aman Tokyo, Park Hyatt Kyoto, and Hakone Ginyu, with breakfast, premium train tickets, some taxis, one Michelin-starred dinner, and a ryokan stay with kaiseki dinner. If you add a private guide for two days and hard-to-book tables, expect closer to EUR 12,000 to EUR 18,000 including taxes. Room categories and dining drive most of the difference."},{"q_fr":"Faut-il un Japan Rail Pass pour un itinéraire 7 jours ?","a_fr":"Non, pas forcément. Sur un itinéraire Tokyo, Kyoto, Hakone en 7 jours, le Japan Rail Pass est souvent moins intéressant qu’avant. Comparez le coût réel de vos trajets, surtout si vous prenez un Nozomi, non inclus dans le pass standard. Le plus simple reste d’acheter séparément Tokyo-Kyoto en Shinkansen, puis Kyoto-Odawara ou Mishima selon votre accès à Hakone. Réservez les sièges Green Car si vous voyagez avec bagages. C’est plus fluide et souvent plus rationnel.","q_en":"Do you need a Japan Rail Pass for a 7-day itinerary?","a_en":"Not necessarily. On a seven-day Tokyo, Kyoto, and Hakone route, the Japan Rail Pass is often less attractive than it used to be. Compare the real cost of your actual train segments, especially if you want to use the Nozomi, which is not included in the standard pass. In practice, separate tickets for Tokyo to Kyoto, then Kyoto to Odawara or Mishima for Hakone, are often simpler. Reserve Green Car seats if you travel with luggage. It is usually smoother and more rational."},{"q_fr":"Quels sont les meilleurs hôtels 5 étoiles à Tokyo ?","a_fr":"À Tokyo, Aman Tokyo reste une référence pour le calme, l’espace et l’accès direct à Otemachi. Le vrai bon geste consiste à descendre au spa avant 7h. Vous aurez souvent la piscine de 30 mètres, face à la Skytree, presque seul. Autres valeurs sûres : Four Seasons Hotel Tokyo at Otemachi, The Peninsula Tokyo pour Ginza et Hibiya, et The Tokyo EDITION, Toranomon pour un séjour plus urbain. Selon le quartier, le bon hôtel change plus que le standing.","q_en":"What are the best five-star hotels in Tokyo?","a_en":"In Tokyo, Aman Tokyo remains a benchmark for calm, generous room sizes, and direct access to Otemachi. The useful insider move is to go down to the spa before 7 a.m. You will often have the 30-meter pool, with Skytree views, almost to yourself. Other strong options are Four Seasons Hotel Tokyo at Otemachi, The Peninsula Tokyo for Ginza and Hibiya, and The Tokyo EDITION, Toranomon for a more urban stay. In Tokyo, neighborhood matters as much as hotel level."},{"q_fr":"Faut-il combiner Tokyo et Kyoto ou rester sur une seule ville ?","a_fr":"Sur 7 jours, combinez Tokyo et Kyoto. Vous verrez deux Japon très différents, reliés en environ 2h10 de Shinkansen Nozomi. Rester sur une seule ville n’a de sens que pour un voyage très lent ou centré sur affaires, gastronomie ou art. Kyoto apporte les sites UNESCO, les ryotei et un rythme plus posé. Tokyo donne la scène contemporaine et les meilleures amplitudes horaires. Le bon équilibre reste 3 nuits Tokyo, 2 Kyoto, 1 Hakone, puis départ.","q_en":"Should you combine Tokyo and Kyoto, or stay in just one city?","a_en":"On a seven-day trip, combine Tokyo and Kyoto. They show two very different sides of Japan, linked by roughly 2 hours 10 minutes on the Nozomi Shinkansen. Staying in only one city makes sense mainly for a slower trip or one focused on business, dining, or art. Kyoto brings UNESCO-listed sites, ryotei dining, and a quieter rhythm. Tokyo delivers the contemporary scene and longer opening hours. The best balance is usually three nights in Tokyo, two in Kyoto, one in Hakone, then departure."},{"q_fr":"Comment se déplacer entre Tokyo, Kyoto et Hakone ?","a_fr":"Le plus fluide est le Shinkansen. Tokyo-Kyoto se fait en environ 2h10 en Nozomi. Kyoto-Hakone passe en général par Odawara, puis taxi ou train local selon l’hôtel. Pour Hakone Ginyu, le taxi depuis Miyanoshita reste le plus simple avec bagages. Entre gares et hôtels, gardez une marge de 20 à 30 minutes. Au Japon, la ponctualité des trains est excellente, mais les correspondances en station peuvent être longues. Faites envoyer les valises séparément si vous changez souvent d’hôtel.","q_en":"How should you travel between Tokyo, Kyoto, and Hakone?","a_en":"The smoothest option is the Shinkansen. Tokyo to Kyoto takes about 2 hours 10 minutes on the Nozomi. Kyoto to Hakone usually means reaching Odawara first, then continuing by taxi or local train depending on the hotel. For Hakone Ginyu, a taxi from Miyanoshita is the easiest choice with luggage. Leave a 20 to 30 minute buffer between stations and hotel arrivals. Japanese trains are highly punctual, but station transfers can still take time. Forwarding luggage separately is worth it on multi-stop trips."},{"q_fr":"Quels restaurants étoilés réserver à Tokyo et Kyoto ?","a_fr":"À Tokyo, pensez à L’Effervescence, trois étoiles Michelin, pour une table française très travaillée, et à Sushi Saito si vous avez un accès hôtelier solide. À Kyoto, Kikunoi Honten, trois étoiles Michelin, reste une grande adresse de kaiseki, tout comme Hyotei, maison historique également triplement étoilée. Réservez deux à trois mois avant, davantage en saison des érables ou des cerisiers. Le vrai levier est le concierge hôtelier. Il obtient parfois les créneaux du déjeuner, plus accessibles que le dîner.","q_en":"Which Michelin-starred restaurants should you book in Tokyo and Kyoto?","a_en":"In Tokyo, consider L’Effervescence, which holds three Michelin stars, for highly refined French cuisine, and Sushi Saito if your hotel concierge has strong access. In Kyoto, Kikunoi Honten, also three Michelin stars, remains a major kaiseki address, as does Hyotei, the historic three-star house. Book two to three months ahead, and even earlier during cherry blossom or autumn foliage periods. The real advantage comes from your hotel concierge, who can sometimes secure lunch slots more easily than dinner."},{"q_fr":"Le Japon est-il adapté pour une lune de miel ?","a_fr":"Oui, très bien, surtout si vous combinez ville, patrimoine et onsen. Tokyo apporte les grandes tables et les suites urbaines. Kyoto donne les temples, les jardins et les ryotei. Hakone ajoute la pause onsen avec dîner en chambre ou kaiseki. Pour un voyage de noces, le détail compte plus que le volume d’étapes. Au Park Hyatt Kyoto, demandez la chambre 3902 ou 3905, côté pagode Yasaka. La vue y est souvent meilleure que dans certaines catégories temple view standard.","q_en":"Is Japan a good choice for a honeymoon?","a_en":"Yes, very much so, especially if you combine city life, heritage, and an onsen stay. Tokyo brings major dining rooms and polished urban suites. Kyoto adds temples, gardens, and ryotei dining. Hakone creates the slower onsen pause, with in-room dinner or kaiseki. For a honeymoon, detail matters more than the number of stops. At Park Hyatt Kyoto, ask for room 3902 or 3905 on the Yasaka Pagoda side. The view is often better than in some standard temple-view categories."},{"q_fr":"Comment réserver un ryokan de luxe à Hakone ?","a_fr":"Réservez tôt, idéalement trois à six mois avant pour les bonnes catégories avec bain privé et vue dégagée. À Hakone Ginyu, vérifiez précisément le type de chambre, l’heure du dîner kaiseki et la politique enfants. Ces points changent l’expérience. Demandez aussi si le transfert depuis Miyanoshita peut être coordonné. Pour une nuit seulement, arrivez avant 16h. Sinon, vous perdez le bain, le dîner et le rythme du ryokan. Le luxe ici tient surtout à la séquence, pas au nombre d’activités.","q_en":"How do you book a luxury ryokan in Hakone?","a_en":"Book early, ideally three to six months ahead, especially for the better room categories with private baths and open views. At Hakone Ginyu, check the exact room type, kaiseki dinner timing, and child policy before confirming. Those details shape the stay. Also ask whether pickup from Miyanoshita can be coordinated. If you are staying only one night, arrive before 4 p.m. Otherwise, you lose the bath, the dinner, and the ryokan rhythm. Here, luxury depends more on timing than on activities."}]'::jsonb,
  '{}'::uuid[],
